// Java 25 - Module import declarations (JEP 511, final)
// Learn: import a whole module's exported packages with one declaration.
// import module exposes exported packages from java.base.
import module java.base;

void main() {
    List<String> langs = List.of("Java", "Kotlin", "Scala");
    Map<String, Integer> lengths = new HashMap<>();
    for (String lang : langs) {
        lengths.put(lang, lang.length());
    }
    IO.println(lengths);
}
